import React, { useState, useEffect } from 'react';
import { Calendar, Plus, Globe, RefreshCw } from 'lucide-react';

const NationalHolidays = ({ onAddHoliday }) => {
  const [nationalHolidays, setNationalHolidays] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedCountry, setSelectedCountry] = useState('US');
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  const countries = [
    { code: 'US', name: 'United States' },
    { code: 'IN', name: 'India' },
    { code: 'GB', name: 'United Kingdom' },
    { code: 'CA', name: 'Canada' },
    { code: 'AU', name: 'Australia' },
    { code: 'DE', name: 'Germany' },
    { code: 'FR', name: 'France' },
    { code: 'JP', name: 'Japan' }
  ];

  const years = Array.from({ length: 5 }, (_, i) => new Date().getFullYear() + i);

  const fetchNationalHolidays = async () => {
    setLoading(true);
    try {
      // Using a free holidays API
      const response = await fetch(
        `https://date.nager.at/api/v3/PublicHolidays/${selectedYear}/${selectedCountry}`
      );

      if (response.ok) {
        const holidays = await response.json();
        setNationalHolidays(holidays);
      } else {
        // Fallback to mock data if API fails
        setNationalHolidays(getMockHolidays());
      }
    } catch (error) {
      console.log('Using mock data due to API error:', error);
      setNationalHolidays(getMockHolidays());
    } finally {
      setLoading(false);
    }
  };

  const getMockHolidays = () => {
    const mockHolidays = {
      US: [
        { name: 'New Year\'s Day', date: `${selectedYear}-01-01`, localName: 'New Year\'s Day' },
        { name: 'Independence Day', date: `${selectedYear}-07-04`, localName: 'Independence Day' },
        { name: 'Thanksgiving Day', date: `${selectedYear}-11-28`, localName: 'Thanksgiving Day' },
        { name: 'Christmas Day', date: `${selectedYear}-12-25`, localName: 'Christmas Day' }
      ],
      IN: [
        { name: 'Republic Day', date: `${selectedYear}-01-26`, localName: 'Republic Day' },
        { name: 'Independence Day', date: `${selectedYear}-08-15`, localName: 'Independence Day' },
        { name: 'Gandhi Jayanti', date: `${selectedYear}-10-02`, localName: 'Gandhi Jayanti' },
        { name: 'Diwali', date: `${selectedYear}-10-20`, localName: 'Diwali' }
      ],
      GB: [
        { name: 'New Year\'s Day', date: `${selectedYear}-01-01`, localName: 'New Year\'s Day' },
        { name: 'Good Friday', date: `${selectedYear}-04-18`, localName: 'Good Friday' },
        { name: 'Christmas Day', date: `${selectedYear}-12-25`, localName: 'Christmas Day' }
      ]
    };

    return mockHolidays[selectedCountry] || mockHolidays.US;
  };

  const handleAddHoliday = (holiday) => {
    const holidayData = {
      name: holiday.name,
      date: holiday.date,
      type: 'national',
      country: selectedCountry
    };

    onAddHoliday(holidayData);
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      weekday: 'long',
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  };

  useEffect(() => {
    fetchNationalHolidays();
  }, [selectedCountry, selectedYear]);

  return (
    <div className="bg-white rounded-lg shadow p-6">
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center space-x-3">
          <div className="p-2 bg-green-100 rounded-lg">
            <Globe className="w-5 h-5 text-green-600" />
          </div>
          <h3 className="text-lg font-semibold text-gray-900">National Holidays</h3>
        </div>
        <button
          onClick={fetchNationalHolidays}
          disabled={loading}
          className="flex items-center space-x-2 px-3 py-2 text-sm font-medium text-green-600 hover:text-green-700 hover:bg-green-50 rounded-lg transition-all duration-200"
        >
          <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
          <span>Refresh</span>
        </button>
      </div>

      {/* Country and Year Selection */}
      <div className="flex flex-col sm:flex-row gap-4 mb-6">
        <div className="flex-1">
          <label className="block text-sm font-medium text-gray-700 mb-2">Country</label>
          <select
            value={selectedCountry}
            onChange={(e) => setSelectedCountry(e.target.value)}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-green-500"
          >
            {countries.map(country => (
              <option key={country.code} value={country.code}>
                {country.name}
              </option>
            ))}
          </select>
        </div>

        <div className="flex-1">
          <label className="block text-sm font-medium text-gray-700 mb-2">Year</label>
          <select
            value={selectedYear}
            onChange={(e) => setSelectedYear(parseInt(e.target.value))}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-green-500"
          >
            {years.map(year => (
              <option key={year} value={year}>{year}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Holidays List */}
      <div className="space-y-3">
        {loading ? (
          <div className="text-center py-8">
            <RefreshCw className="w-8 h-8 text-green-600 animate-spin mx-auto mb-2" />
            <p className="text-gray-600">Loading holidays...</p>
          </div>
        ) : nationalHolidays.length > 0 ? (
          nationalHolidays.map((holiday, index) => (
            <div key={index} className="flex items-center justify-between p-4 bg-gray-50 rounded-lg border border-gray-200">
              <div className="flex-1">
                <h4 className="font-medium text-gray-900">{holiday.name}</h4>
                <p className="text-sm text-gray-600">{formatDate(holiday.date)}</p>
                {holiday.localName && holiday.localName !== holiday.name && (
                  <p className="text-xs text-gray-500 mt-1">{holiday.localName}</p>
                )}
              </div>

              <button
                onClick={() => handleAddHoliday(holiday)}
                className="flex items-center space-x-2 px-3 py-2 text-sm font-medium text-green-600 hover:text-green-700 hover:bg-green-50 rounded-lg transition-all duration-200 border border-green-200 hover:border-green-300"
              >
                <Plus className="w-4 h-4" />
                <span>Add</span>
              </button>
            </div>
          ))
        ) : (
          <div className="text-center py-8 text-gray-600">
            <Calendar className="w-12 h-12 text-gray-400 mx-auto mb-2" />
            <p>No holidays found for the selected country and year.</p>
          </div>
        )}
      </div>

      <div className="mt-6 p-4 bg-blue-50 rounded-lg border border-blue-200">
        <p className="text-sm text-blue-800">
          <strong>Tip:</strong> Click "Add" next to any holiday to add it to your personal calendar. 
          You can then manage these holidays in the Holiday Management section.
        </p>
      </div>
    </div>
  );
};

export default NationalHolidays;
